CustomField.formula:
IF(
    ISPICKVAL(Statut__c, "Terminé"), 
    /* Option 1: Laisser vide une fois terminé */
    NULL, 
    IF(
        ISBLANK(Date_de_fin__c),
        NULL,
        /* Calcul : Date de fin moins aujourd'hui */
        /* Si Date de fin est passée, le résultat sera négatif*/
        ROUND(Date_de_fin__c - NOW(), 0)
    )
)
